const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else if (i % 2 === 1) {
        input.push(parseInt(line));
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
        let n = input[i - 1];
        let arr = input[i];
        arr.sort((a, b) => a - b);
        let median = arr[Math.floor(n / 2)];
        let sum = 0;
        for (let j = 0; j < n; j++) {
            sum += Math.abs(arr[j] - median);
        }
        console.log(sum);
        input = [];
        if (i / 2 === t) {
            process.exit();
        }
    }
    i++;
});

